-- Conversations table with automatic expiry column
CREATE TABLE conversations (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id     UUID NOT NULL,
    messages    JSONB NOT NULL,
    created_at  TIMESTAMPTZ DEFAULT now(),
    expires_at  TIMESTAMPTZ DEFAULT now() + INTERVAL '90 days'
);

-- Index for efficient pruning
CREATE INDEX ON conversations (expires_at);

-- Scheduled deletion job (run daily via pg_cron or external cron)
DELETE FROM conversations WHERE expires_at < now();

def export_user_data(user_id: str) -> dict:
    return {
        # From your own DB — conversation history
        "conversations": db.query(
            "SELECT id, created_at, messages FROM conversations "
            "WHERE user_id = %s ORDER BY created_at DESC",
            [user_id]
        ),
        # Token usage metadata from Admin API (no prompt content)
        # Anthropic does not expose per-user usage via the API;
        # you must derive this from your own usage tracking
        "usage_summary": db.query(
            "SELECT date, input_tokens, output_tokens FROM usage_log "
            "WHERE user_id = %s",
            [user_id]
        )
    }

import json

def export_portable_data(user_id: str) -> str:
    rows = db.query(
        "SELECT created_at, messages FROM conversations "
        "WHERE user_id = %s ORDER BY created_at",
        [user_id]
    )
    export = [
        {"timestamp": r["created_at"].isoformat(), "messages": r["messages"]}
        for r in rows
    ]
    return json.dumps({"user_id": user_id, "conversations": export}, indent=2)
